css:
@page { size: A4; margin: 15mm; }
body { font-family: 'Helvetica', Arial, sans-serif; color: #333; }
.header { text-align: center; margin-bottom: 20px; }
.header h1 { color: #247DBD; margin: 0; font-size: 24px; }
.header h3 { color: #666; margin: 5px 0; font-size: 14px; }
.invoice-info { display: flex; justify-content: space-between; margin: 15px 0; padding: 10px 0; border-top: 2px solid #247DBD; border-bottom: 2px solid #247DBD; }
.client-info { margin: 10px 0; }
.client-info h4 { margin: 0 0 5px 0; color: #247DBD; }
table.items { width: 100%; border-collapse: collapse; margin: 15px 0; }
table.items th { background: #247DBD; color: white; padding: 8px; text-align: left; font-size: 12px; }
table.items td { padding: 6px 8px; border-bottom: 1px solid #eee; font-size: 11px; }
table.items tr:nth-child(even) { background: #f9f9f9; }
.totals { float: right; width: 300px; margin: 15px 0; }
.totals table { width: 100%; }
.totals td { padding: 5px; font-size: 12px; }
.totals .grand-total { font-weight: bold; font-size: 16px; color: #247DBD; }
.footer { position: fixed; bottom: 0; width: 100%; text-align: center; font-size: 10px; color: #999; border-top: 1px solid #ddd; padding-top: 10px; }
.vat-info { font-size: 10px; color: #666; margin: 5px 0; }
.qr-code { float: right; margin: 10px; }
